import React from 'react';

const StatusBadge = ({ status, className = '' }) => {
  const statusConfig = {
    pending: { label: 'Pending', className: 'status-pending px-3 py-1 rounded-full text-xs font-medium' },
    paid: { label: 'Paid', className: 'bg-green-100 text-green-800 px-3 py-1 rounded-full text-xs font-medium dark:bg-green-900 dark:text-green-100' },
    draft: { label: 'Draft', className: 'status-draft px-3 py-1 rounded-full text-xs font-medium' },
  };

  const config = statusConfig[status] || statusConfig.draft;

  return (
    <span className={`${config.className} ${className}`}>
      {config.label}
    </span>
  );
};

export default StatusBadge;
